const subscribers = $input.all().map(i => i.json);
const now = new Date();
const oneDayAgo = new Date(now - 24 * 60 * 60 * 1000);
const sevenDaysAgo = new Date(now - 7 * 24 * 60 * 60 * 1000);
const thirtyDaysAgo = new Date(now - 30 * 24 * 60 * 60 * 1000);

const total = subscribers.length;
const confirmed = subscribers.filter(s =>
  s.status === 'confirmed' || s.confirmed === 'true' || s.confirmed === true
).length;
const pending = subscribers.filter(s => s.status === 'pending').length;
const unsubscribed = subscribers.filter(s => s.status === 'unsubscribed').length;

// Growth metrics
const newToday = subscribers.filter(s => {
  const d = new Date(s.subscribed_at);
  return d >= oneDayAgo;
}).length;

const newThisWeek = subscribers.filter(s => {
  const d = new Date(s.subscribed_at);
  return d >= sevenDaysAgo;
}).length;

const newThisMonth = subscribers.filter(s => {
  const d = new Date(s.subscribed_at);
  return d >= thirtyDaysAgo;
}).length;

const confirmationRate = total > 0 ? Math.round((confirmed / total) * 100) : 0;

// Top sources
const sourceCounts = {};
for (const s of subscribers) {
  const src = s.source || 'unknown';
  sourceCounts[src] = (sourceCounts[src] || 0) + 1;
}
const topSources = Object.entries(sourceCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([source, count]) => `${source}: ${count}`)
  .join(', ');

return [{
  json: {
    total,
    confirmed,
    pending,
    unsubscribed,
    new_today: newToday,
    new_this_week: newThisWeek,
    new_this_month: newThisMonth,
    confirmation_rate: confirmationRate,
    top_sources: topSources,
    report_date: now.toISOString().split('T')[0]
  }
}];
